UPDATE coaching.exercise SET
  name = 'Kettlebell Goblet Squat',
  description = 'Perform Kettlebell Goblet Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
