UPDATE coaching.exercise SET
  name = 'Kettlebell Box Squat',
  description = 'Perform Kettlebell Box Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
  card_summary = 'Kettlebell Box Squat is a kettlebell-loaded strength exercise for position consistency, depth control, and force production from a repeatable target. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.',
  coach_language = 'Primary subrole: Box-supported squat strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.',
  athlete_language = 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.',
  movement_family = 'Box-supported squat strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'squat_knee_dominant_strength',
  primary_order_slot = 'kettlebell_box_squat_strength',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 45,
