  coaching_execution = '{"movement_description":"Kettlebell Goblet Squat Iso Hold trains bottom-position squat strength, joint ownership, and positional tension without speed using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a kettlebell load the athlete can control for every rep.","Set feet, grip, ribs, and pelvis before beginning the movement.","Brace and breathe so the bell stays close to the body and the rep path stays repeatable."],"execution_steps":["Lower into the target position with control and stop where alignment can be owned.","Hold tension through the feet, hips, trunk, and hands without collapsing or breath-holding.","Keep the kettlebell quiet and the posture unchanged for the target time.","Exit the hold before alignment fails, then reset before the next set."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Foot tripod, knees track, chest/ribs stacked.","Stand through the floor, not around the position."],"athlete_cues":["Strong and clean beats heavy and sloppy.","Stop before the bell controls you.","Make the last rep look like the first rep."],"breathing_cues":["Inhale to prepare and brace before the hard part.","Exhale through the effort without losing trunk position.","Do not use long breath holds with youth, beginners, older adults, or pregnancy/postpartum athletes."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Knees collapse inward or feet lose tripod pressure.","Depth is forced by rounding the spine instead of owning hip and ankle range."],"quality_gate":["Pain-free range of motion.","Kettlebell path stays controlled.","Posture remains organized under load.","Athlete can stop the set before grip or alignment fails."],"stop_signs":["Sharp pain or joint pinching.","Grip becomes unsafe or bell path becomes uncontrolled.","Spine, shoulder, hip, knee, ankle, or wrist position cannot be maintained.","Breath-holding, dizziness, or pressure symptoms dominate the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Posterior-chain accessory","Loaded carry","Restore / cooldown"],"pairs_well_after":["Ankle mobility","Bodyweight squat patterning","Glute activation"],"good_for_sessions":["squat_prep","strength_accessory"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot control the kettlebell safely.","Pain appears in the loaded pattern.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex kettlebell strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Kettlebell Goblet Squat Iso Hold from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
