UPDATE coaching.exercise SET
  name = 'Kettlebell Single-Leg Box Squat',
  description = 'Perform Kettlebell Single-Leg Box Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
