  coach_language = 'Primary subrole: Single-leg box squat strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.',
  athlete_language = 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.',
  movement_family = 'Single-leg box squat strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'squat_knee_dominant_strength',
  primary_order_slot = 'kettlebell_single_leg_box_squat_strength',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["single_leg_squat_to_box","knee_flexion_extension","hip_control","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors","foot_intrinsics"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Kettlebell Single-Leg Box Squat trains single-leg squat strength with a consistent target and controlled range using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a kettlebell load the athlete can control for every rep.","Set feet, grip, ribs, and pelvis before beginning the movement.","Brace and breathe so the bell stays close to the body and the rep path stays repeatable."],"execution_steps":["Move into the single-leg pattern with the front foot rooted and trunk stacked.","Lower under control until the target depth is reached without knee collapse or torso drift.","Drive through the working leg to return to the start while keeping the kettlebell quiet.","Reset balance and posture before the next rep or side switch."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Foot tripod, knees track, chest/ribs stacked.","Stand through the floor, not around the position."],"athlete_cues":["Strong and clean beats heavy and sloppy.","Stop before the bell controls you.","Make the last rep look like the first rep."],"breathing_cues":["Inhale to prepare and brace before the hard part.","Exhale through the effort without losing trunk position.","Do not use long breath holds with youth, beginners, older adults, or pregnancy/postpartum athletes."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Knees collapse inward or feet lose tripod pressure.","Depth is forced by rounding the spine instead of owning hip and ankle range."],"quality_gate":["Pain-free range of motion.","Kettlebell path stays controlled.","Posture remains organized under load.","Athlete can stop the set before grip or alignment fails."],"stop_signs":["Sharp pain or joint pinching.","Grip becomes unsafe or bell path becomes uncontrolled.","Spine, shoulder, hip, knee, ankle, or wrist position cannot be maintained.","Breath-holding, dizziness, or pressure symptoms dominate the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Posterior-chain accessory","Loaded carry","Restore / cooldown"],"pairs_well_after":["Ankle mobility","Bodyweight squat patterning","Glute activation"],"good_for_sessions":["squat_prep","strength_accessory"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot control the kettlebell safely.","Pain appears in the loaded pattern.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex kettlebell strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Kettlebell Single-Leg Box Squat from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
