-- Kettlebell Deadlift (kettlebell-deadlift)
UPDATE coaching.exercise SET
  name = 'Kettlebell Deadlift',
  description = 'Perform Kettlebell Deadlift as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
  card_summary = 'Kettlebell Deadlift is a kettlebell-loaded strength exercise for dead-start hip and leg drive with a simple bell path and strong bracing. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.',
  coach_language = 'Primary subrole: Deadlift strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.',
  athlete_language = 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.',
  movement_family = 'Deadlift strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'hinge_posterior_chain_strength',
  primary_order_slot = 'kettlebell_deadlift_strength',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["hip_hinge","hip_extension","knee_extension","trunk_bracing"],"primary_tissues":["glutes","hamstrings","spinal_erectors","lats"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Kettlebell Deadlift trains dead-start hip and leg drive with a simple bell path and strong bracing using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Place the kettlebell(s) close enough that the athlete can reach without rounding.","Set the feet, hinge the hips, pack the shoulders, and brace before loading the handle.","Create tension through the floor and handle before the bell leaves the ground or changes direction."],"execution_steps":["Push the floor away and extend the hips while keeping the kettlebell close.","Reach the top with glutes and trunk engaged, not with the ribs flared.","Lower by hinging the hips back while the spine stays long and the handle path stays controlled.","Reset tension before each rep instead of bouncing or rushing."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Hips back, spine long, bell close.","Finish tall with glutes, not low-back arch."],"athlete_cues":["Strong and clean beats heavy and sloppy.","Stop before the bell controls you.","Make the last rep look like the first rep."],"breathing_cues":["Inhale to prepare and brace before the hard part.","Exhale through the effort without losing trunk position.","Do not use long breath holds with youth, beginners, older adults, or pregnancy/postpartum athletes."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Rounding the back or reaching the bell away from the body.","Squatting the hinge when the goal is posterior-chain loading."],"quality_gate":["Pain-free range of motion.","Kettlebell path stays controlled.","Posture remains organized under load.","Athlete can stop the set before grip or alignment fails."],"stop_signs":["Sharp pain or joint pinching.","Grip becomes unsafe or bell path becomes uncontrolled.","Spine, shoulder, hip, knee, ankle, or wrist position cannot be maintained.","Breath-holding, dizziness, or pressure symptoms dominate the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Upper-body push or pull","Loaded carry","Restore / cooldown"],"pairs_well_after":["Hip hinge drill","Glute bridge","Hamstring activation"],"good_for_sessions":["general_warmup","strength_accessory"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot control the kettlebell safely.","Pain appears in the loaded pattern.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex kettlebell strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Kettlebell Deadlift from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
