UPDATE coaching.exercise SET
  name = 'Single-Leg Kettlebell RDL',
  description = 'Perform Single-Leg Kettlebell RDL as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
