-- Kettlebell Floor Press (kettlebell-floor-press)
UPDATE coaching.exercise SET
  name = 'Kettlebell Floor Press',
  description = 'Perform Kettlebell Floor Press as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
  card_summary = 'Kettlebell Floor Press is a kettlebell-loaded strength exercise for horizontal pressing strength with a floor stop that controls shoulder range. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.',
  coach_language = 'Primary subrole: Floor press strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.',
  athlete_language = 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.',
  movement_family = 'Floor press strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'upper_body_push_strength',
  primary_order_slot = 'kettlebell_floor_press_strength',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["horizontal_press","elbow_extension","shoulder_horizontal_adduction","trunk_bracing"],"primary_tissues":["pectorals","triceps","anterior_deltoids","rotator_cuff"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Kettlebell Floor Press trains horizontal pressing strength with a floor stop that controls shoulder range using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Lie on the floor or mat with the kettlebell(s) placed where they can be reached safely.","Set feet, ribs, and pelvis before unracking or rolling the bell into position.","Pack the shoulder and keep the wrist stacked before the first rep."],"execution_steps":["Lower the kettlebell with control until the target stop point is reached.","Keep wrist, elbow, shoulder, ribs, and pelvis organized at the bottom.","Press with strong intent while keeping the rest of the body quiet and stable.","Finish the rep under control, reset the breath and shoulder, then repeat."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Stack wrist over elbow; press from a packed shoulder.","Ribs down as the bell moves."],"athlete_cues":["Strong and clean beats heavy and sloppy.","Stop before the bell controls you.","Make the last rep look like the first rep."],"breathing_cues":["Inhale to prepare and brace before the hard part.","Exhale through the effort without losing trunk position.","Do not use long breath holds with youth, beginners, older adults, or pregnancy/postpartum athletes."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Pressing with rib flare, neck tension, or wrist collapse.","Losing shoulder position at the bottom or overhead finish."],"quality_gate":["Pain-free range of motion.","Kettlebell path stays controlled.","Posture remains organized under load.","Athlete can stop the set before grip or alignment fails."],"stop_signs":["Sharp pain or joint pinching.","Grip becomes unsafe or bell path becomes uncontrolled.","Spine, shoulder, hip, knee, ankle, or wrist position cannot be maintained.","Breath-holding, dizziness, or pressure symptoms dominate the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Upper-body pull","Loaded carry","Restore / cooldown"],"pairs_well_after":["Scapular activation","T-spine access","Breathing/bracing reset"],"good_for_sessions":["overhead_prep","strength_accessory"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot control the kettlebell safely.","Pain appears in the loaded pattern.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex kettlebell strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Kettlebell Floor Press from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
  updated_at = now()
WHERE slug = 'kettlebell-floor-press';

