UPDATE coaching.exercise SET
  name = 'Double Kettlebell Strict Press',
  description = 'Perform Double Kettlebell Strict Press as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
