-- Kettlebell Gorilla Row (kettlebell-gorilla-row)
UPDATE coaching.exercise SET
  name = 'Kettlebell Gorilla Row',
  description = 'Perform Kettlebell Gorilla Row as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
  card_summary = 'Kettlebell Gorilla Row is a kettlebell-loaded strength exercise for alternating pull strength with hinge-position endurance and trunk control. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.',
  coach_language = 'Primary subrole: Gorilla row strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.',
  athlete_language = 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.',
  movement_family = 'Gorilla row strength',
