  movement_requirements = '{"primary_joint_actions":["alternating_horizontal_pull","hip_hinge_hold","anti_rotation_bracing","scapular_control"],"primary_tissues":["lats","rhomboids","obliques","spinal_erectors","forearm_grip"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Kettlebell Gorilla Row trains alternating pull strength with hinge-position endurance and trunk control using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Set a strong hinge or supported stance before touching the bell.","Grip the kettlebell, pack the shoulder, and brace the trunk before pulling.","Keep the neck neutral and choose a range that can be controlled without twisting."],"execution_steps":["Pull the kettlebell toward the body while the trunk position stays fixed.","Finish the pull with the shoulder blade moving back and down, not the neck shrugging.","Lower the bell with control until the arm is long but posture is unchanged.","Reset the brace before each rep or side switch."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Hips back, spine long, bell close.","Finish tall with glutes, not low-back arch.","Pull elbow toward hip; shoulder blade back and down.","Quiet torso, strong grip."],"athlete_cues":["Strong and clean beats heavy and sloppy.","Stop before the bell controls you.","Make the last rep look like the first rep."],"breathing_cues":["Inhale to prepare and brace before the hard part.","Exhale through the effort without losing trunk position.","Do not use long breath holds with youth, beginners, older adults, or pregnancy/postpartum athletes."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Rounding the back or reaching the bell away from the body.","Squatting the hinge when the goal is posterior-chain loading.","Shrugging instead of pulling with the upper back.","Twisting the trunk to create range instead of rowing with control."],"quality_gate":["Pain-free range of motion.","Kettlebell path stays controlled.","Posture remains organized under load.","Athlete can stop the set before grip or alignment fails."],"stop_signs":["Sharp pain or joint pinching.","Grip becomes unsafe or bell path becomes uncontrolled.","Spine, shoulder, hip, knee, ankle, or wrist position cannot be maintained.","Breath-holding, dizziness, or pressure symptoms dominate the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Upper-body push or pull","Loaded carry","Restore / cooldown"],"pairs_well_after":["Hip hinge drill","Glute bridge","Hamstring activation"],"good_for_sessions":["general_warmup","strength_accessory"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot control the kettlebell safely.","Pain appears in the loaded pattern.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex kettlebell strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Kettlebell Gorilla Row from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
