  impact_level = 0,
  requires_spotting = FALSE,
  requires_coach_supervision = 'recommended',
  readiness_checks = ARRAY['Athlete can demonstrate the unloaded pattern without pain.', 'Athlete can brace and breathe without dizziness.', 'Athlete can stop the set before technique deteriorates.', 'Athlete can set the kettlebell down safely.']::text[],
  contraindications = ARRAY['Painful joint loading in the pattern.', 'Uncontrolled spine, shoulder, hip, knee, ankle, or wrist position.', 'No safe space, grip, or support for the variation.']::text[],
  common_substitutions = ARRAY['Bottoms-up hold', 'Suitcase carry', 'Front-rack carry']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'kettlebell-bottoms-up-carry';

-- Kettlebell Turkish Get-Up (kettlebell-turkish-get-up)
UPDATE coaching.exercise SET
  name = 'Kettlebell Turkish Get-Up',
  description = 'Perform Kettlebell Turkish Get-Up as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
  card_summary = 'Kettlebell Turkish Get-Up is a kettlebell-loaded strength exercise for whole-body strength, shoulder ownership, and trunk control through multiple positions. Strength and control are the primary scores; explosiveness should not be treated as the main intent.',
  coach_language = 'Primary subrole: Get-up strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.',
  athlete_language = 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.',
  movement_family = 'Get-up strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'carry_trunk_loaded_bracing_strength',
  primary_order_slot = 'kettlebell_turkish_get_up_strength',
  default_sets = 3,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["loaded_roll_to_elbow","shoulder_lockout","hip_bridge","half_kneeling_transition","loaded_stand"],"primary_tissues":["rotator_cuff","deltoids","obliques","glutes","quadriceps","forearm_grip"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Kettlebell Turkish Get-Up trains whole-body strength, shoulder ownership, and trunk control through multiple positions using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Start with a light kettlebell and rehearse the bodyweight path first.","Set the working shoulder, wrist, ribs, and eyes before the loaded rep begins.","Clear the space around the athlete so the bell can be lowered safely at any point."],"execution_steps":["Roll to the elbow and hand while keeping the kettlebell stacked over the shoulder.","Bridge or sweep the leg into a stable half-kneeling position without losing the overhead line.","Stand tall under control, then reverse the same path back to the floor.","Pause at each checkpoint long enough to prove the shoulder, trunk, and hip positions are owned."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Hips back, spine long, bell close.","Finish tall with glutes, not low-back arch.","Stack wrist over elbow; press from a packed shoulder.","Ribs down as the bell moves."],"athlete_cues":["Strong and clean beats heavy and sloppy.","Stop before the bell controls you.","Make the last rep look like the first rep."],"breathing_cues":["Inhale to prepare and brace before the hard part.","Exhale through the effort without losing trunk position.","Do not use long breath holds with youth, beginners, older adults, or pregnancy/postpartum athletes."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Rounding the back or reaching the bell away from the body.","Squatting the hinge when the goal is posterior-chain loading.","Pressing with rib flare, neck tension, or wrist collapse.","Losing shoulder position at the bottom or overhead finish."],"quality_gate":["Pain-free range of motion.","Kettlebell path stays controlled.","Posture remains organized under load.","Athlete can stop the set before grip or alignment fails."],"stop_signs":["Sharp pain or joint pinching.","Grip becomes unsafe or bell path becomes uncontrolled.","Spine, shoulder, hip, knee, ankle, or wrist position cannot be maintained.","Breath-holding, dizziness, or pressure symptoms dominate the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Upper-body push or pull","Loaded carry","Restore / cooldown"],"pairs_well_after":["Hip hinge drill","Glute bridge","Hamstring activation"],"good_for_sessions":["general_warmup","strength_accessory"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot control the kettlebell safely.","Pain appears in the loaded pattern.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex kettlebell strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Kettlebell Turkish Get-Up from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
  updated_at = now()
WHERE slug = 'kettlebell-turkish-get-up';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'kettlebell_turkish_get_up_strength',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 4,
  fatigue_cost = 4,
  technical_complexity = 5,
  impact_level = 0,
  intensity_ceiling = 'high',
  notes = ''
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'capacity'
JOIN coaching.phase_order_slot pos ON pos.key = 'kettlebell_turkish_get_up_strength' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'kettlebell-turkish-get-up';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'reps',
  default_sets = 3,
  default_reps = 3,
  default_distance = NULL::integer,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 60,
  default_rpe_min = 6,
  default_rpe_max = 8,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'kettlebell-turkish-get-up';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = 3,
  minimum_hours_between_hard_exposures = 48,
  counts_as_high_intensity = TRUE,
  counts_as_high_impact = FALSE,
  counts_as_neural = TRUE,
  counts_as_tissue_stress = TRUE,
  counts_as_conditioning = FALSE
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'kettlebell-turkish-get-up';

