-- Kettlebell Windmill (kettlebell-windmill)
UPDATE coaching.exercise SET
  name = 'Kettlebell Windmill',
  description = 'Perform Kettlebell Windmill as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.',
  card_summary = 'Kettlebell Windmill is a kettlebell-loaded strength exercise for loaded hinge-rotation strength with shoulder stability and trunk control. Strength and control are the primary scores; explosiveness should not be treated as the main intent.',
  coach_language = 'Primary subrole: Windmill strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.',
  athlete_language = 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.',
  movement_family = 'Windmill strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'carry_trunk_loaded_bracing_strength',
  primary_order_slot = 'kettlebell_windmill_strength',
  default_sets = 3,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["hip_hinge_with_rotation","overhead_lockout","thoracic_rotation_control","anti_lateral_flexion"],"primary_tissues":["obliques","glutes","hamstrings","rotator_cuff","upper_back"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Kettlebell Windmill trains loaded hinge-rotation strength with shoulder stability and trunk control using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Start with a light kettlebell and rehearse the bodyweight path first.","Set the working shoulder, wrist, ribs, and eyes before the loaded rep begins.","Clear the space around the athlete so the bell can be lowered safely at any point."],"execution_steps":["Set the kettlebell overhead and angle the feet so the hips can hinge safely.","Push the hips back and rotate the torso only as far as shoulder position remains stacked.","Drive through the hips and trunk to return to standing without bending the overhead arm.","Move slowly enough that the bell, ribs, and pelvis stay organized the entire rep."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Hips back, spine long, bell close.","Finish tall with glutes, not low-back arch.","Rotate only through the range you own.","Shoulder stacked, hips do the work."],"athlete_cues":["Strong and clean beats heavy and sloppy.","Stop before the bell controls you.","Make the last rep look like the first rep."],"breathing_cues":["Inhale to prepare and brace before the hard part.","Exhale through the effort without losing trunk position.","Do not use long breath holds with youth, beginners, older adults, or pregnancy/postpartum athletes."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Rounding the back or reaching the bell away from the body.","Squatting the hinge when the goal is posterior-chain loading.","Rotating through the low back instead of controlling hips, ribs, and shoulder stack."],"quality_gate":["Pain-free range of motion.","Kettlebell path stays controlled.","Posture remains organized under load.","Athlete can stop the set before grip or alignment fails."],"stop_signs":["Sharp pain or joint pinching.","Grip becomes unsafe or bell path becomes uncontrolled.","Spine, shoulder, hip, knee, ankle, or wrist position cannot be maintained.","Breath-holding, dizziness, or pressure symptoms dominate the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Upper-body push or pull","Loaded carry","Restore / cooldown"],"pairs_well_after":["Hip hinge drill","Glute bridge","Hamstring activation"],"good_for_sessions":["general_warmup","strength_accessory"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot control the kettlebell safely.","Pain appears in the loaded pattern.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex kettlebell strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","NSCA-style resistance training exercise technique standards"],"internal_notes":["Film Kettlebell Windmill from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
  updated_at = now()
WHERE slug = 'kettlebell-windmill';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'kettlebell_windmill_strength',
  order_index = pos.order_index,
