-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and force/tissue capacity for kettlebell strength in the Capacity phase.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('kettlebell-goblet-squat', 'The kettlebell gives the athlete a compact but demanding external resistance problem. Its handle, bell shape, and common rack/offset positions require grip, shoulder organization, trunk stiffness, and force production without needing high-impact or jump-based explosiveness.', 'Belongs in Capacity because the main adaptation is loaded force production, tissue tolerance, and structural reserve. It may support later explosiveness when coached with intent, but it should not replace true Output work.', 'Use in the Capacity phase after Prepare/Access, Movement Intelligence, and any true Output work. Keep it before hard conditioning; use enough rest to preserve strength-quality reps and clean kettlebell control.', 'The most common mistake is turning a strength lift into a rushed fatigue circuit, a ballistic swing-style drill, or over-tagging it as explosiveness simply because the athlete moves hard. Keep load, tempo, rest, and technique aligned with strength first.', 'Scale by kettlebell load, range of motion, base of support, tempo, set length, and rest. Progress only when posture, pain-free range, grip security, and repeatable rep quality are stable.'),
